import React, { useEffect, useRef, useState } from 'react';
import { Box, AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemIcon, ListItemText } from '@mui/material';
import { fabric } from 'fabric';
import styled from 'styled-components';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon,
} from '@mui/icons-material';

const CanvasContainer = styled(Box)`
  flex-grow: 1;
  height: calc(100vh - 64px);
  background: white;
`;

const ToolbarButton = styled(IconButton)`
  margin: 0 8px;
`;

const App = () => {
  const canvasRef = useRef(null);
  const [canvas, setCanvas] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [currentColor, setCurrentColor] = useState('#000000');
  const [currentWidth, setCurrentWidth] = useState(2);

  useEffect(() => {
    const canvas = new fabric.Canvas(canvasRef.current, {
      width: window.innerWidth - 240,
      height: window.innerHeight - 64,
      backgroundColor: '#ffffff',
    });

    setCanvas(canvas);

    return () => {
      canvas.dispose();
    };
  }, []);

  const addShape = (shape) => {
    if (!canvas) return;

    let object;
    switch (shape) {
      case 'rectangle':
        object = new fabric.Rect({
          left: 100,
          top: 100,
          width: 100,
          height: 100,
          fill: 'transparent',
          stroke: currentColor,
          strokeWidth: currentWidth,
        });
        break;
      case 'circle':
        object = new fabric.Circle({
          left: 100,
          top: 100,
          radius: 50,
          fill: 'transparent',
          stroke: currentColor,
          strokeWidth: currentWidth,
        });
        break;
      default:
        return;
    }

    canvas.add(object);
    canvas.setActiveObject(object);
  };

  const handleUndo = () => {
    if (!canvas) return;
    if (canvas._objects.length > 0) {
      canvas.remove(canvas._objects[canvas._objects.length - 1]);
    }
  };

  const handleClear = () => {
    if (!canvas) return;
    canvas.clear();
  };

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            Draze - Where Shapes Take Form
          </Typography>
          <ToolbarButton color="inherit" onClick={() => setDrawerOpen(true)}>
            <BrushIcon />
          </ToolbarButton>
          <ToolbarButton color="inherit" onClick={handleUndo}>
            <UndoIcon />
          </ToolbarButton>
          <ToolbarButton color="inherit" onClick={handleClear}>
            <DeleteIcon />
          </ToolbarButton>
        </Toolbar>
      </AppBar>

      <Drawer
        anchor="left"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
      >
        <List sx={{ width: 240 }}>
          <ListItem button onClick={() => addShape('rectangle')}>
            <ListItemIcon>
              <BrushIcon />
            </ListItemIcon>
            <ListItemText primary="Rectangle" />
          </ListItem>
          <ListItem button onClick={() => addShape('circle')}>
            <ListItemIcon>
              <BrushIcon />
            </ListItemIcon>
            <ListItemText primary="Circle" />
          </ListItem>
          <ListItem>
            <ListItemIcon>
              <ColorLensIcon />
            </ListItemIcon>
            <input
              type="color"
              value={currentColor}
              onChange={(e) => setCurrentColor(e.target.value)}
            />
          </ListItem>
        </List>
      </Drawer>

      <CanvasContainer>
        <canvas ref={canvasRef} />
      </CanvasContainer>
    </Box>
  );
};

export default App;
